6	describe("parse ini", () => {
7	  test("weird section", () => {
8	    const ini = /* ini */ `
9	[foo\\]]
10	lol = true
11	`;
12	
13	    expect(parse(ini)).toEqual({ "[foo\\]]": true, "lol": true });
14	  });
15	
16	  test("really long input", () => {
17	    const ini = /* ini */ `
18	[${Array(1024).fill("a").join("")}.lol.this.be.long]
19	wow = 'hi'
20	`;
21	
22	    expect(parse(ini)).toEqual({
23	      [`${Array(1024).fill("a").join("")}`]: {
24	        lol: {
25	          this: {
26	            be: {
27	              long: {
28	                wow: "hi",
29	              },
30	            },
31	          },
32	        },
33	      },
34	    });
35	  });
36	  describe("env vars", () => {
37	    // Tests translated from npm's workspaces/config/test/env-replace.js
38	    envVarTest({
39	      name: "replaces multiple defined variables",
40	      ini: "hi = ${FOO}${BAR}",
41	      env: { FOO: "bar", BAR: "baz" },
42	      expected: { hi: "barbaz" },
43	    });
44	
45	    envVarTest({
46	      name: "replaces mixed defined/undefined variables with ? modifier",
