36	pub fn stringify(
37	    global: *jsc.JSGlobalObject,
38	    callFrame: *jsc.CallFrame,
39	) bun.JSError!jsc.JSValue {
40	    const value = callFrame.argument(0);
41	
42	    if (value.isEmptyOrUndefinedOrNull()) {
43	        return global.throwInvalidArguments("Expected an object to stringify", .{});
44	    }
45	
46	    if (!value.isObject()) {
47	        return global.throw("INI.stringify expects a plain object", .{});
48	    }
49	
50	    var builder: wtf.StringBuilder = .init();
51	    defer builder.deinit();
