60	fn stringifyObject(global: *jsc.JSGlobalObject, value: jsc.JSValue, builder: *wtf.StringBuilder, section: ?bun.String) StringifyError!void {
61	    const obj = try value.toObject(global);
62	    var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(global, obj);
63	    defer iter.deinit();
64	
65	    // First pass: emit non-object (scalar) properties
66	    while (try iter.next()) |prop_name| {
67	        const prop_val = iter.value;
68	        if (prop_val.isObject() and !prop_val.isString() and !prop_val.isArray() and !prop_val.isDate()) {
69	            continue; // handle sections in second pass
70	        }
71	        if (section != null) {
72	            // scalars inside sections are emitted after the header
73	        }
74	        builder.append(.string, prop_name);
75	        builder.append(.latin1, " = ");
76	        try appendValue(global, prop_val, builder);
77	        builder.append(.lchar, '\n');
78	    }
79	
80	    // Second pass: emit sections (nested objects)
81	    iter.reset();
82	    while (try iter.next()) |prop_name| {
83	        const prop_val = iter.value;
84	        if (!prop_val.isObject() or prop_val.isString() or prop_val.isArray() or prop_val.isDate()) {
85	            continue;
86	        }
87	        builder.append(.lchar, '\n');
88	        builder.append(.lchar, '[');
89	        builder.append(.string, prop_name);
90	        builder.append(.latin1, "]\n");
91	        try stringifySection(global, prop_val, builder);
92	    }
93	}
