pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(global, bun.default_allocator);
    defer input_slice.deinit();

    const source = input_slice.slice();
    return parseINI(global, source) catch |err| switch (err) {
        error.JSError => error.JSError,
        error.OutOfMemory => error.OutOfMemory,
    };
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected an object to stringify", .{});
    }

    if (!value.isObject()) {
        return global.throw("INI.stringify expects a plain object", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    try stringifyObject(global, value, &builder, null);

    return builder.toString(global);
}

const StringifyError = bun.JSError || error{OutOfMemory};

fn stringifyObject(global: *jsc.JSGlobalObject, value: jsc.JSValue, builder: *wtf.StringBuilder, section: ?bun.String) StringifyError!void {
    const obj = try value.toObject(global);
    var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(global, obj);
    defer iter.deinit();

    // First pass: emit non-object (scalar) properties
    while (try iter.next()) |prop_name| {
        const prop_val = iter.value;
        if (prop_val.isObject() and !prop_val.isString() and !prop_val.isArray() and !prop_val.isDate()) {
            continue; // handle sections in second pass
        }
        if (section != null) {
            // scalars inside sections are emitted after the header
        }
        builder.append(.string, prop_name);
        builder.append(.latin1, " = ");
        try appendValue(global, prop_val, builder);
        builder.append(.lchar, '\n');
    }

    // Second pass: emit sections (nested objects)
    iter.reset();
    while (try iter.next()) |prop_name| {
        const prop_val = iter.value;
        if (!prop_val.isObject() or prop_val.isString() or prop_val.isArray() or prop_val.isDate()) {
            continue;
        }
        builder.append(.lchar, '\n');
        builder.append(.lchar, '[');
        builder.append(.string, prop_name);
        builder.append(.latin1, "]\n");
        try stringifySection(global, prop_val, builder);
    }
}

fn stringifySection(global: *jsc.JSGlobalObject, value: jsc.JSValue, builder: *wtf.StringBuilder) StringifyError!void {
    const obj = try value.toObject(global);
    var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(global, obj);
    defer iter.deinit();

    while (try iter.next()) |prop_name| {
        const prop_val = iter.value;
        builder.append(.string, prop_name);
        builder.append(.latin1, " = ");
        try appendValue(global, prop_val, builder);
        builder.append(.lchar, '\n');
    }
}

fn appendValue(global: *jsc.JSGlobalObject, value: jsc.JSValue, builder: *wtf.StringBuilder) StringifyError!void {
    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        return;
    }
    if (value.isNull()) {
        builder.append(.latin1, "null");
        return;
    }
    if (value.isUndefined()) {
        return;
    }
    if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
        return;
    }
    // Default: convert to string
    const str = try value.toBunString(global);
    defer str.deref();
    builder.append(.string, str);
}

const ParseError = error{ JSError, OutOfMemory };

fn parseINI(global: *jsc.JSGlobalObject, source: []const u8) ParseError!jsc.JSValue {
    const root = JSValue.createEmptyObject(global, 0);
    var current_section = root;
    var line_num: u32 = 0;

    var remaining = source;
    while (remaining.len > 0) {
        // Find end of line
        const line_end = std.mem.indexOfScalar(u8, remaining, '\n') orelse remaining.len;
        const raw_line = remaining[0..line_end];
        remaining = if (line_end < remaining.len) remaining[line_end + 1 ..] else &.{};
        line_num += 1;

        // Strip \r for CRLF
        const line_cr = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        // Trim leading/trailing whitespace
        const line = std.mem.trim(u8, line_cr, &std.ascii.whitespace);

        // Skip empty lines and comments
        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header
        if (line[0] == '[') {
            if (line[line.len - 1] != ']') {
                return global.throw("INI parse error: unterminated section header at line {d}", .{line_num});
            }
            const section_name = std.mem.trim(u8, line[1 .. line.len - 1], &std.ascii.whitespace);
            if (section_name.len == 0) {
                return global.throw("INI parse error: empty section name at line {d}", .{line_num});
            }
            // Create the section object if it doesn't exist yet, or reuse existing
            var name_str = bun.String.borrowUTF8(section_name);
            const existing = try root.getWithBunString(global, &name_str);
            if (existing.isEmptyOrUndefinedOrNull()) {
                const section_obj = JSValue.createEmptyObject(global, 0);
                try root.putMayBeIndex(global, &name_str, section_obj);
                current_section = section_obj;
            } else {
                current_section = existing;
            }
            continue;
        }

        // Key=value pair
        const eq_pos = std.mem.indexOfScalar(u8, line, '=') orelse {
            return global.throw("INI parse error: expected '=' in key-value pair at line {d}", .{line_num});
        };

        const key = std.mem.trim(u8, line[0..eq_pos], &std.ascii.whitespace);
        if (key.len == 0) {
            return global.throw("INI parse error: empty key at line {d}", .{line_num});
        }

        const raw_val = std.mem.trim(u8, line[eq_pos + 1 ..], &std.ascii.whitespace);

        // Strip inline comments (only if preceded by whitespace)
        const val = stripInlineComment(raw_val);

        // Convert value to appropriate JS type
        const js_val = parseValue(global, val);
        var key_str = bun.String.borrowUTF8(key);
        try current_section.putMayBeIndex(global, &key_str, js_val);
    }

    return root;
}

fn stripInlineComment(val: []const u8) []const u8 {
    // Look for ; or # preceded by whitespace (not inside quotes)
    var in_single_quote = false;
    var in_double_quote = false;
    var i: usize = 0;
    while (i < val.len) : (i += 1) {
        const c = val[i];
        if (c == '\'' and !in_double_quote) {
            in_single_quote = !in_single_quote;
        } else if (c == '"' and !in_single_quote) {
            in_double_quote = !in_double_quote;
        } else if ((c == ';' or c == '#') and !in_single_quote and !in_double_quote) {
            if (i > 0 and isWhitespace(val[i - 1])) {
                return std.mem.trim(u8, val[0 .. i - 1], &std.ascii.whitespace);
            }
        }
    }
    return val;
}

fn isWhitespace(c: u8) bool {
    return c == ' ' or c == '\t';
}

fn parseValue(global: *jsc.JSGlobalObject, val: []const u8) jsc.JSValue {
    if (val.len == 0) {
        return .js_undefined;
    }

    // Check for quoted strings
    if (val.len >= 2) {
        if ((val[0] == '"' and val[val.len - 1] == '"') or
            (val[0] == '\'' and val[val.len - 1] == '\''))
        {
            const unquoted = val[1 .. val.len - 1];
            var str = bun.String.borrowUTF8(unquoted);
            defer str.deref();
            return str.toJS(global);
        }
    }

    // Boolean
    if (std.ascii.eqlIgnoreCase(val, "true") or std.ascii.eqlIgnoreCase(val, "yes") or std.ascii.eqlIgnoreCase(val, "on")) {
        return .jsBoolean(true);
    }
    if (std.ascii.eqlIgnoreCase(val, "false") or std.ascii.eqlIgnoreCase(val, "no") or std.ascii.eqlIgnoreCase(val, "off")) {
        return .jsBoolean(false);
    }

    // Null
    if (std.ascii.eqlIgnoreCase(val, "null") or std.ascii.eqlIgnoreCase(val, "none")) {
        return .null;
    }

    // Integer
    if (std.fmt.parseInt(i64, val, 10)) |int_val| {
        if (int_val >= std.math.minInt(i32) and int_val <= std.math.maxInt(i32)) {
            return .jsNumber(@as(i32, @intCast(int_val)));
        }
        return .jsNumber(@as(f64, @floatFromInt(int_val)));
    } else |_| {}

    // Float
    if (std.fmt.parseFloat(f64, val)) |float_val| {
        return .jsNumber(float_val);
    } else |_| {}

    // Default: string
    var str = bun.String.borrowUTF8(val);
    defer str.deref();
    return str.toJS(global);
}

const std = @import("std");

const bun = @import("bun");

const jsc = bun.jsc;
const JSValue = jsc.JSValue;
const ZigString = jsc.ZigString;
const wtf = jsc.wtf;

